mapper.delete:
DELETE FROM TBL_POST
WHERE POST_NUMBER = #{value}
  AND POST_TYPE = 'QNA_POST'

mapper.update:
UPDATE TBL_POST
SET ANSWER_STATUS = '답변완료'
WHERE POST_NUMBER = #{value}

UPDATE TBL_POST
SET ANSWER_STATUS = '답변대기'
WHERE POST_NUMBER = #{value}

mapper.select:
SELECT COUNT(*)
FROM TBL_COMMENT
WHERE POST_NUMBER = #{value}

SELECT * FROM ( SELECT ROWNUM AS RNUM, A.* FROM ( SELECT P.POST_NUMBER, P.POST_TITLE, U.USER_ID AS USER_ID, C.COMPANY_NAME AS COMPANY_NAME, TO_CHAR(P.POST_DATE, 'YYYY-MM-DD') AS POST_DATE, P.ANSWER_STATUS, P.VIEW_COUNT FROM TBL_POST P JOIN TBL_USER U ON P.USER_NUMBER = U.USER_NUMBER JOIN TBL_COMPANY C ON P.COMPANY_NUMBER = C.COMPANY_NUMBER WHERE P.POST_TYPE = 'QNA_POST'
AND P.COMPANY_NUMBER = #{companyNumber}
ORDER BY P.POST_NUMBER DESC ) A ) WHERE RNUM BETWEEN #{startRow} AND #{endRow}
